import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import KycUpload from './KycUpload';
import ChangePassword from './ChangePassword';
import Deposit from './Deposit';

const Dashboard = () => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const loadProfile = async () => {
    const token = localStorage.getItem('token');
    if (!token) {
      navigate('/login');
      return;
    }
    try {
      const res = await axios.get('http://localhost:5000/api/auth/profile', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setUser(res.data);
    } catch (err) {
      setError('Unable to load profile. Please login again.');
      localStorage.removeItem('token');
      navigate('/login');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadProfile();
  }, []);

  const handleBalanceUpdate = (newBalance) => {
    setUser(prev => ({ ...prev, balance: newBalance }));
  };

  return (
    <section className="dashboard-page">
      <div className="dashboard-header">
        <h2>Welcome back, {user?.username || 'user'}</h2>
        <p className="subtitle">Your account balance and wallet tools are below.</p>
      </div>
      {loading ? (
        <div className="card">Loading dashboard...</div>
      ) : error ? (
        <div className="card error">{error}</div>
      ) : (
        <div className="dashboard-grid">
          <div className="card balance-card">
            <h3>Account balance</h3>
            <p className="balance-value">${user.balance.toFixed(2)}</p>
            <p>Account email: {user.email}</p>
            <p>KYC documents uploaded: {user.kycDocuments?.length || 0}</p>
            <p>Status: {user.isKycVerified ? 'Verified' : 'Pending'}</p>
          </div>

          <div className="card">
            <h3>Upload KYC documents</h3>
            <KycUpload onSuccess={loadProfile} />
          </div>

          <div className="card">
            <h3>Change password</h3>
            <ChangePassword />
          </div>

          <div className="card">
            <h3>Deposit funds</h3>
            <Deposit onDepositSuccess={handleBalanceUpdate} />
          </div>
        </div>
      )}
    </section>
  );
};

export default Dashboard;
